class Solution {
public:
    int countVowelPermutation(int n) {
        const int MOD = 1e9 + 7;
        vector<long long> dp(5, 1);
        vector<vector<int>> next = {{1}, {0, 2}, {0, 1, 3, 4}, {3, 4}, {0}};

        for (int _ = 1; _ < n; ++_) {
            vector<long long> newDp(5, 0);
            for (int j = 0; j < 5; ++j) {
                for (int k : next[j]) {
                    newDp[k] = (newDp[k] + dp[j]) % MOD;
                }
            }
            dp = newDp;
        }

        long long res = 0;
        for (int i = 0; i < 5; ++i) {
            res = (res + dp[i]) % MOD;
        }
        return res;
    }
};
